protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // EF Core 9 breaking change: discriminator property renamed from "Discriminator" to "$type".
    // Keep the old name for backward compatibility with existing documents.
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // EF Core 9 breaking change: id format changed from "EntityType|Key" to just "Key".
    // Preserve the old format so existing documents remain accessible.
    modelBuilder.Entity<Blog>().HasPartitionKey(b => b.Id);
    modelBuilder.Entity<Blog>().Property(b => b.Id)
        .HasJsonPropertyName("id");
    modelBuilder.Entity<Blog>()
        .ToContainer("Blogs")
        .HasNoDiscriminator();
}

protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
{
    // Opt out of the new id format to keep "Discriminator|Key" ids
    // compatible with existing documents
}

